import{_ as a,o as i,c as e,ae as t}from"./chunks/framework.D8e0q88G.js";const c=JSON.parse('{"title":"Backend Overview","description":"","frontmatter":{},"headers":[],"relativePath":"backend/overview.md","filePath":"backend/overview.md"}'),n={name:"backend/overview.md"};function r(l,s,h,p,d,o){return i(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="backend-overview" tabindex="-1">Backend Overview <a class="header-anchor" href="#backend-overview" aria-label="Permalink to &quot;Backend Overview&quot;">​</a></h1><p><strong>File:</strong> <code>backend/server.py</code></p><p>The backend is a lean FastAPI application. Its sole job is to accept a video file, run pose estimation on every frame, and stream the results back to the browser. It contains no business logic — all metric computation happens on the frontend.</p><h2 id="tech-stack" tabindex="-1">Tech Stack <a class="header-anchor" href="#tech-stack" aria-label="Permalink to &quot;Tech Stack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concern</th><th>Library</th></tr></thead><tbody><tr><td>Framework</td><td>FastAPI (async)</td></tr><tr><td>Pose estimation</td><td>RTMLib — MMPose Wholebody3d</td></tr><tr><td>Video I/O</td><td>OpenCV (<code>cv2</code>)</td></tr><tr><td>Inference runtime</td><td>ONNX Runtime (CPU)</td></tr><tr><td>Transport</td><td>Server-Sent Events (SSE)</td></tr></tbody></table><h2 id="startup" tabindex="-1">Startup <a class="header-anchor" href="#startup" aria-label="Permalink to &quot;Startup&quot;">​</a></h2><p>On startup, the server initialises the pose tracker once:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">tracker </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PoseTracker(</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Wholebody3d,</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    det_frequency</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">7</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># re-run detection every 7 frames; track between</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    tracking</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">False</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    backend</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;onnxruntime&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    device</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cpu&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p><code>det_frequency=7</code> means the person detector runs every 7 frames and tracking propagates the bounding box in between. This is a performance trade-off: full detection on every frame is more accurate but significantly slower on CPU.</p><p>A warmup pass is run immediately after initialisation to avoid cold-start latency on the first real video:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">blank </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> np.zeros((</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">64</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">64</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">dtype</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">np.uint8)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">tracker(blank)</span></span></code></pre></div><h2 id="cors" tabindex="-1">CORS <a class="header-anchor" href="#cors" aria-label="Permalink to &quot;CORS&quot;">​</a></h2><p>CORS is configured to allow all origins:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">app.add_middleware(CORSMiddleware, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">allow_origins</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;*&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>This is appropriate for local use (browser and server on the same machine). If deploying to a remote server, restrict <code>allow_origins</code> to your frontend&#39;s actual origin.</p><h2 id="temporary-file-handling" tabindex="-1">Temporary File Handling <a class="header-anchor" href="#temporary-file-handling" aria-label="Permalink to &quot;Temporary File Handling&quot;">​</a></h2><p>Uploaded videos are written to a system temp file with the original file extension preserved. The temp file is always deleted in a <code>finally</code> block after streaming completes, even if inference fails midway.</p><h2 id="model-weights" tabindex="-1">Model Weights <a class="header-anchor" href="#model-weights" aria-label="Permalink to &quot;Model Weights&quot;">​</a></h2><p>RTMLib downloads ONNX model weights on first run and caches them locally. The Wholebody3d model is larger than the standard body-only models — expect a download of several hundred MB on first startup.</p>`,19)])])}const E=a(n,[["render",r]]);export{c as __pageData,E as default};
